var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"신호패턴 분석 중......","JPN":"シグナルパターン分析中……","ENG":"Analyzing the signal pattern...","TWN":"正在分析信號模式……"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"좌표 확인 완료.","JPN":"座標確認完了。","ENG":"Coordinates confirmed.","TWN":"完成座標確認。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"정보가 파악되지 않은 초고심도 포인트로 차원항로를 설정합니다.","JPN":"情報把握がされていない超高深度ポイントに次元航路を設定します。","ENG":"Setting interdimensional course to the unknown hyperdepths.","TWN":"將次元航路設置為無任何情報的超深度地點。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MECHANIC_RAZANGRIFF_SKILL_START"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이터니움 드라이브 온라인.","JPN":"エタニウムドライブ、オンライン。","ENG":"Eternium Drive online.","TWN":"永恆之金引擎連線。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_22"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"강하.","JPN":"降下。","ENG":"Descending.","TWN":"降落。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MECHANIC_GRAYSTATION_HYPER_SKILL_START"},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"곧 목적지에 도착할 겁니다.","JPN":"間もなく目的地に到着します。","ENG":"We'll arrive at the destination soon.","TWN":"即將到達目的地。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"항해하는 동안 좌석은 편안하셨는지 궁금하네요.","JPN":"今回の航海はお気に召しましたか。","ENG":"Was your Dive comfortable?","TWN":"不知道航行期間座位是否舒適呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런 쓸데없는 질문은 할 필요 없다.","JPN":"そんなくだらない質問は必要ない。","ENG":"No need to ask such a silly question.","TWN":"不要問那種無聊的問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 확실히 놀랍군.","JPN":"だが確かに驚きではあるな。","ENG":"But this ship is certainly astounding.","TWN":"但確實令人吃驚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 정도의 차원 압력을 뚫고 단숨에 초고심도로 진입하는 함선이라니......","JPN":"このレベルの次元圧力を突破して一気に超高深度に進入する艦船なんて……","ENG":"A ship that can withstand this level of dimensional pressure and reach the hyperdepths immediately...","TWN":"這艦船竟然能一口氣突破這種程度的次元壓力，進入超深度……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"합중국의 어떤 차원함선도 이런 성능을 가진 것은 없어.","JPN":"合衆国のどの次元艦船にも、このような性能はない。","ENG":"No one else in the States has a dimensional ship with such impressive performance.","TWN":"聯邦的任何次元戰艦都不具備這樣的性能。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"강습함 글레입니르는 구 관리국에서도 최강의 전대가 사용하던 전용함이니까요.","JPN":"強襲艦グレイプニルは、旧管理局でも最強の戦隊が使用していた専用艦です。","ENG":"This Assault Ship, Gleipnir, was once used by the Old Administration's strongest division.","TWN":"因為強襲戰艦格萊伊尼勒在舊管理局也是最強戰隊使用的專用艦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신들이 만든 그 모조품들과 비교할 수는 없는 법이죠.","JPN":"あなた方が作った模造品とは比べ物にならないでしょう。","ENG":"It can't be compared to the imitations that you've made.","TWN":"你們製造的那些仿造品完全無法與之相比。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 좋은 배가 있다고 해서 반드시 항해가 성공하는 건 아니에요.","JPN":"しかし良い船があるからといって、必ず航海が成功するわけではありません。","ENG":"But a good ship alone doesn't guarantee a successful voyage.","TWN":"但就算有好艦船，也不能保證航行一定能成功。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"원하는 항구로 가려면 제대로 된 나침반과 지도가 필요합니다.","JPN":"目的の港に向うためには、正確なコンパスと地図が必要です。","ENG":"You need a proper compass and map to arrive at the destination safely.","TWN":"想到達要去的港口，還需要有好的羅盤和地圖。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 제공해 준 네임리스 원의 침식파 시그니처가 정확하다면 좋겠군요.","JPN":"あなたが提供してくれたネームレスワンの侵食波シグネチャーが正確であることを祈ります。","ENG":"I hope the Nameless One's Corruption ray signature you gave us is accurate.","TWN":"希望你提供的無名1侵蝕波信號是正確的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"엉뚱한 좌표에서 시간낭비를 하는 건 피차 원하는 바가 아니니까요.","JPN":"誤った座標で時間を無駄にするのは、お互いに望むことではありませんので。","ENG":"We don't want to waste time in the wrong place.","TWN":"我們誰都不想因為錯誤的座標而浪費時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런 걱정은 말도록.","JPN":"心配無用だ。","ENG":"No need to worry.","TWN":"不用擔心那種問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그건 놈과의 전투 중에 내가 직접 수집한 데이터다.","JPN":"それは奴との戦闘中に私が直接収集したデータだ。","ENG":"I collected the data myself while fighting against that one.","TWN":"因為那是我在跟那傢伙戰鬥時親自收集的資料。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"잘못될 가능성은 통계상 1% 미만이지.","JPN":"誤りがある可能性は統計上1％未満である。","ENG":"Statistically, the possibility of it being compromised is less than one percent.","TWN":"發生錯誤的可能性，從統計學來說跟本不足1%。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇다면야 저도 안심이네요.","JPN":"それなら僕も安心です。","ENG":"Well, I'm relieved to hear that.","TWN":"這樣的話，我就放心了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네임리스 원의 유해를 찾아낸다면 우리의 프로젝트에도 큰 도움이 될 테니까요.","JPN":"ネームレスワンの遺骸を見つけられたら、我々のプロジェクトにも大いに役立つでしょう。","ENG":"Finding the remains of the Nameless One will be of great help to our project.","TWN":"如果能找到無名1的遺骸，對我們的計畫也有巨大幫助。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"죄송합니다, 레지날드 부사령관님.","JPN":"申し訳ございません、レジナルド副司令官。","ENG":"I'm sorry, Deputy Commander.","TWN":"對不起，多明尼克副司令官大人。"},"stage":{"bg":"black","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"멈춰, 제이나! 명령이다!","JPN":"止まれ、ジェイナ！　命令だ！","ENG":"Stop, Jaina! That's an order!","TWN":"站住，婕娜！這是命令！"},"stage":{"bg":"black","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"자네 잘못이 아니야, 도미닉.","JPN":"君のせいではない、ドミニーク。","ENG":"It's not your fault, Dominic.","TWN":"不是你的錯誤，多明尼克。"},"stage":{"bg":"black","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"제이나, 그 아이에게 자네는......","JPN":"ジェイナ、あの子にとって君は……","ENG":"To Jaina, you were...","TWN":"婕娜，對那個孩子來說你是……"},"stage":{"bg":"black","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"표정이 별로 안 좋아 보이는군요. 잊고 온 물건이라도 생각났나요?","JPN":"顔色がよくないですね。忘れ物でもありましたか？","ENG":"You don't look so happy. Is there something you left behind?","TWN":"你的表情看起來很糟糕。是想起了什麼已經被忘記的事情嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......그냥 물어보고 싶은 게 하나 있군.","JPN":"……一つ聞きたいことがある。","ENG":"I just have one question.","TWN":"沒……我想問你一個問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"만약 오래 전, 초고심도에 추락한 카운터가 있다면......","JPN":"もしずいぶん前に超高深度に墜落したカウンターがいるとしたら……","ENG":"If there was a Counter who fell into the hyperdepths a long time ago...","TWN":"如果很久以前，有制裁者因故墜落到超高深度地點……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"혹시 그 사람이 살아있을 가능성이 있을까?","JPN":"その人物が生きている可能性は万が一にもあるだろうか？","ENG":"Is there a chance that person might be still alive?","TWN":"那個人有生存下來的可能性嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"흐음, 글쎄요.","JPN":"さあ、どうでしょう。","ENG":"Hmm, I don't know.","TWN":"嗯，這很難說。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"일반적인 경우라면 그런 상황에 처한 사람이 살아남는 건 불가능에 가깝겠죠.","JPN":"一般的な場合、そのような状況に置かれた人が生き残るのは不可能に近いでしょう。","ENG":"Normally, it would be almost impossible for a person to survive under such circumstances.","TWN":"如果是一般情況，處在那種狀況下的人幾乎不可能存活。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"역시 그렇겠지.","JPN":"やはりそうか。","ENG":"I thought so.","TWN":"果然，是這樣才對吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 예전에 제 스승님께서 말씀하신 적이 있습니다.","JPN":"しかし昔、師匠がこうおっしゃっていました。","ENG":"But my Master once told me.","TWN":"但以前我的老師說過一句話。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이면세계란 원래 아무것도 확신할 수 없는 곳이라고.","JPN":"裏世界は、何事も確信できない場所だと。","ENG":"You can never be certain about anything in the Counterside.","TWN":"所謂異界，本來就是任何東西都無法確信的地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니 아주 운이 좋다면...... 꼭 불가능한 것만은 아니지 않을까요?","JPN":"ですのでとても運が良ければ……絶対不可能とは言えないでしょうね。","ENG":"So if this person is very lucky... there still exists the possibility of survival.","TWN":"所以如果運氣好的話…… 也不是完全沒可能吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......그렇군.","JPN":"……そうか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"서두르는 편이 좋겠어.","JPN":"急いだほうが良さそうだ。","ENG":"We should hurry.","TWN":"我們加快進度吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};